hard.solution:
def repl():
    while True:
        try:
            code = input(">>> ")
            if code in ('exit','quit'): break
            result = eval(code)
            if result is not None: print(result)
        except KeyboardInterrupt: break
        except Exception as e: print(f"Error: {e}")
